import { useEffect, useState } from "react";
import axios from "axios";
import { FiSearch, FiHeart } from "react-icons/fi";
import Banner from "../components/Banner";
import "../assets/style.css";

export default function MainPage() {
  const [items, setItems] = useState([]);
  const [searchValue, setSearchValue] = useState("");

  useEffect(() => {
    axios
      .get("https://f468684b9fb74495.mokky.dev/sneakerslist")
      .then((response) => {
        setItems(response.data);
      })
      .catch((error) => {
        console.error("Ошибка при получении товаров:", error);
      });
  }, []);

  const filteredItems = items.filter((item) =>
    item.title.toLowerCase().includes(searchValue.toLowerCase())
  );

  return (
    <div className="wrapper">
      <Header />
      <div className="content">
        <Banner />

        <div className="content__top">
          <h1>{searchValue ? `Поиск: ${searchValue}` : "Все кроссовки"}</h1>

          <div className="search-block">
            <FiSearch size={18} className="search-icon" />
            <input
              type="text"
              placeholder="Поиск..."
              value={searchValue}
              onChange={(e) => setSearchValue(e.target.value)}
            />
          </div>
        </div>

        <div className="cards">
          {filteredItems.map((item) => (
            <div className="card" key={item.id}>
              <button className="card__favorite">
                <FiHeart size={18} />
              </button>

              <img className="card__image" src={item.imageUrl} alt={item.title} />

              <h5 className="card__title">{item.title}</h5>

              <div className="card__bottom">
                <div className="card__price-block">
                  <span>Цена:</span>
                  <b>{item.price.toLocaleString("ru-RU")} руб.</b>
                </div>

                <button className="card__add">+</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
